-- Migration 0005: Kenyan Medicine Master Database + Inventory Management
-- This is the comprehensive preloaded database of medicines available in Kenya.
-- Admins/pharmacists only manage stock quantities, not create medicines from scratch.

-- =========================================================================
-- INVENTORY MANAGEMENT TABLES
-- =========================================================================

CREATE TABLE IF NOT EXISTS suppliers (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  contact_person TEXT,
  phone TEXT,
  email TEXT,
  address TEXT,
  created_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TABLE IF NOT EXISTS stock_batches (
  id TEXT PRIMARY KEY,
  medicine_id TEXT NOT NULL REFERENCES medicines(id),
  supplier_id TEXT REFERENCES suppliers(id),
  batch_number TEXT NOT NULL,
  quantity INTEGER NOT NULL,
  purchase_price REAL NOT NULL,
  selling_price REAL,
  expiry_date TEXT NOT NULL,
  received_date TEXT NOT NULL DEFAULT (datetime('now')),
  notes TEXT
);
CREATE INDEX IF NOT EXISTS idx_batches_medicine ON stock_batches(medicine_id);
CREATE INDEX IF NOT EXISTS idx_batches_expiry ON stock_batches(expiry_date);

