 ('km_ibuprofen', 'cat_pain_killers', 'Brufen', 'Ibuprofen', 'Abbott', '400mg', 'Tablet', 180, 0, 600, '', 'Anti-inflammatory pain reliever for stronger pain.', 'Pain, inflammation, fever, arthritis, period pain', '1 tablet 2-3 times daily with food', 'Stomach upset, nausea, dizziness', 'Take with food. Avoid if peptic ulcer. Caution in asthma.', 'Store below 25°C', 0, 1, 4.6),
 ('km_ibuprofen_susp', 'cat_pain_killers', 'Brufen Syrup', 'Ibuprofen', 'Abbott', '100mg/5ml', 'Suspension', 280, 0, 350, '', 'Ibuprofen syrup for children pain and fever.', 'Fever, pain, inflammation in children', 'As per age/weight on包装', 'Stomach upset, nausea', 'Take with food. Not for children under 3 months.', 'Store below 25°C', 0, 0, 4.5),
 ('km_diclofenac', 'cat_pain_killers', 'Voltaren', 'Diclofenac', 'Novartis', '50mg', 'Tablet', 220, 0, 400, '', 'Strong anti-inflammatory for joint and muscle pain.', 'Arthritis, back pain, joint pain, muscle sprains', '1 tablet 2-3 times daily with food', 'Stomach pain, nausea, dizziness, fluid retention', 'Take with food. Avoid in peptic ulcer and kidney disease.', 'Store below 25°C', 1, 0, 4.4),
 ('km_diclofenac_gel', 'cat_pain_killers', 'Voltaren Emulgel', 'Diclofenac', 'Novartis', '1%', 'Gel', 350, 0, 300, '', 'Topical anti-inflammatory gel for localized pain.', 'Joint pain, muscle sprains, sports injuries', 'Apply thin layer 3-4 times daily', 'Skin irritation at application site', 'Do not use on broken skin. Avoid sun exposure.', 'Store below 25°C', 0, 0, 4.5),
 ('km_aspirin', 'cat_pain_killers', 'Disprin', 'Aspirin', 'Reckitt', '300mg', 'Tablet', 120, 0, 500, '', 'Pain reliever and blood thinner.', 'Headache, fever, pain, prevention of blood clots', '1-2 tablets as needed. Dissolve in water.', 'Stomach upset, bleeding risk', 'Not for children under 16 (Reye''s syndrome). Avoid in bleeding disorders.', 'Store below 25°C', 0, 0, 4.3),
 ('km_naproxen', 'cat_pain_killers', 'Naprosyn', 'Naproxen', 'Roche', '250mg', 'Tablet', 300, 0, 200, '', 'Long-acting anti-inflammatory for persistent pain.', 'Arthritis, back pain, period pain, gout', '1 tablet twice daily with food', 'Stomach upset, dizziness, headache', 'Take with food. Avoid in kidney disease and peptic ulcer.', 'Store below 25°C', 1, 0, 4.3),
 ('km_tramadol', 'cat_pain_killers', 'Tramal', 'Tramadol', 'Grünenthal', '50mg', 'Capsule', 400, 0, 150, '', 'Strong pain reliever for moderate to severe pain.', 'Severe pain, post-surgical pain, cancer pain', '1 capsule every 6 hours as prescribed', 'Nausea, constipation, dizziness, drowsiness', 'Controlled substance. Risk of dependence. Prescription required.', 'Store below 25°C', 1, 0, 4.2),
