 ('km_meloxicam', 'cat_pain_killers', 'Mobic', 'Meloxicam', 'Boehringer', '15mg', 'Tablet', 350, 0, 180, '', 'Once-daily anti-inflammatory for arthritis.', 'Osteoarthritis, rheumatoid arthritis', '1 tablet once daily with food', 'Stomach upset, dizziness, headache', 'Take with food. Avoid in kidney disease.', 'Store below 25°C', 1, 0, 4.3),
 ('km_ketorolac', 'cat_pain_killers', 'Toradol', 'Ketorolac', 'Roche', '10mg', 'Tablet', 450, 0, 120, '', 'Potent short-term pain relief.', 'Severe acute pain (short-term use only)', '1 tablet every 4-6 hours. Max 5 days.', 'Stomach upset, dizziness, headache', 'Max 5 days use. Avoid in kidney disease and peptic ulcer.', 'Store below 25°C', 1, 0, 4.2),
 ('km_piroxicam', 'cat_pain_killers', 'Feldene', 'Piroxicam', 'Pfizer', '20mg', 'Capsule', 280, 0, 200, '', 'Long-acting anti-inflammatory.', 'Arthritis, joint pain', '1 capsule daily with food', 'Stomach upset, dizziness, rash', 'Take with food. Not for elderly without monitoring.', 'Store below 25°C', 1, 0, 4.1),
